import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { ChevronLeft, ChevronRight, Trash2, X, Save, AlertCircle } from 'lucide-react';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);
  const [cartoes, setCartoes] = useState([]);
  const [usuarios, setUsuarios] = useState([]);
  const [perfilLogado, setPerfilLogado] = useState(null);
  const [itemParaEditar, setItemParaEditar] = useState(null);
  const [filtroData, setFiltroData] = useState({
    mes: new Date().getMonth(),
    ano: new Date().getFullYear()
  });

  const mesesNominais = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  useEffect(() => {
    carregarDadosIniciais();
  }, [filtroData]);

  async function carregarDadosIniciais() {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const { data: meuPerfil } = await supabase.from('profiles').select('*').eq('id', user.id).single();
    setPerfilLogado(meuPerfil);

    // Busca listas para o modal (apenas proprietário edita)
    if (meuPerfil?.tipo_usuario === 'proprietario') {
      const { data: dCartoes } = await supabase.from('cartoes').select('id, nome').order('nome');
      const { data: dUsers } = await supabase.from('profiles').select('id, nome').order('nome');
      setCartoes(dCartoes || []);
      setUsuarios(dUsers || []);
    }

    fetchDespesas(meuPerfil);
  }

  async function fetchDespesas(perfil) {
    // Busca compras trazendo o nome de quem está no user_id
    let query = supabase.from('compras').select('*, profiles(nome)');

    // Se não for proprietário, só vê o que já está vinculado ao seu ID
    if (perfil?.tipo_usuario !== 'proprietario') {
      query = query.eq('user_id', perfil.id);
    }

    const { data, error } = await query;

    if (!error && data) {
      const projetadas = [];
      data.forEach(item => {
        const numParcelas = item.num_parcelas || 1;
        for (let i = 0; i < numParcelas; i++) {
          const [ano, mes, dia] = item.data_compra.split('-');
          const dataCompra = new Date(ano, mes - 1, dia);
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);
          
          if (dataParcela.getMonth() === filtroData.mes && dataParcela.getFullYear() === filtroData.ano) {
            projetadas.push({
              ...item,
              parcelaAtual: i + 1,
              valorParcela: parseFloat(item.valor_total) / numParcelas,
              nomeResponsavel: item.profiles?.nome || "⚠️ Vincular" 
            });
          }
        }
      });
      setDespesas(projetadas.sort((a,b) => b.data_compra.localeCompare(a.data_compra)));
    }
  }

  const handleUpdate = async (e) => {
    e.preventDefault();
    const { error } = await supabase
      .from('compras')
      .update({
        descricao: itemParaEditar.descricao,
        loja: itemParaEditar.loja,
        user_id: itemParaEditar.user_id, 
        valor_total: parseFloat(itemParaEditar.valor_total),
        cartao: itemParaEditar.cartao
      })
      .eq('id', itemParaEditar.id);

    if (error) alert("Erro: " + error.message);
    else {
      setItemParaEditar(null);
      fetchDespesas(perfilLogado);
    }
  };

  const mudarMes = (direcao) => {
    let novoMes = filtroData.mes + direcao;
    let novoAno = filtroData.ano;
    if (novoMes < 0) { novoMes = 11; novoAno--; }
    else if (novoMes > 11) { novoMes = 0; novoAno++; }
    setFiltroData({ mes: novoMes, ano: novoAno });
  };

  return (
    <div className="fade-in" style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <h2>Extrato de Gastos</h2>
        <div style={{ display: 'flex', gap: '10px', background: 'white', padding: '8px', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}>
          <button onClick={() => mudarMes(-1)} style={navBtnStyle}><ChevronLeft /></button>
          <span style={{ fontWeight: 'bold', minWidth: '120px', textAlign: 'center' }}>
            {mesesNominais[filtroData.mes]} {filtroData.ano}
          </span>
          <button onClick={() => mudarMes(1)} style={navBtnStyle}><ChevronRight /></button>
        </div>
      </div>

      <div className="card" style={{ padding: 0, overflowX: 'auto' }}>
        <table style={{ width: '100%', minWidth: '800px', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: '#f8fafc', textAlign: 'left' }}>
              <th style={tHead}>Data</th>
              <th style={tHead}>Responsável</th>
              <th style={tHead}>Descrição</th>
              <th style={tHead}>Parcela</th>
              <th style={{...tHead, textAlign: 'right'}}>Valor</th>
            </tr>
          </thead>
          <tbody>
            {despesas.map((item, idx) => (
              <tr 
                key={`${item.id}-${idx}`} 
                onClick={() => perfilLogado?.tipo_usuario === 'proprietario' && setItemParaEditar(item)}
                style={{ borderTop: '1px solid #f1f5f9', cursor: perfilLogado?.tipo_usuario === 'proprietario' ? 'pointer' : 'default' }}
              >
                <td style={tCell}>{item.data_compra.split('-').reverse().slice(0,2).join('/')}</td>
                <td style={{...tCell, color: item.profiles?.nome ? '#4361ee' : '#f43f5e', fontWeight: 'bold'}}>
                  {item.nomeResponsavel}
                </td>
                <td style={tCell}>{item.descricao}</td>
                <td style={tCell}>{item.parcelado ? `${item.parcelaAtual}/${item.num_parcelas}` : 'À Vista'}</td>
                <td style={{...tCell, textAlign: 'right', fontWeight: 'bold'}}>
                  R$ {item.valorParcela.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {itemParaEditar && (
        <div className="modal-overlay" style={overlayStyle}>
          <div className="modal-content" style={{ maxWidth: '450px', padding: '30px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h3 style={{ margin: 0 }}>Vincular Responsável</h3>
              <X onClick={() => setItemParaEditar(null)} style={{ cursor: 'pointer' }} />
            </div>

            <form onSubmit={handleUpdate} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
              <div>
                <label style={labelStyle}>Quem pagou?</label>
                <select 
                  className="form-control" 
                  value={itemParaEditar.user_id || ''} 
                  onChange={e => setItemParaEditar({...itemParaEditar, user_id: e.target.value})}
                  required
                >
                  <option value="">Selecione um perfil...</option>
                  {usuarios.map(u => (
                    <option key={u.id} value={u.id}>{u.nome}</option>
                  ))}
                </select>
              </div>

              <div>
                <label style={labelStyle}>Descrição</label>
                <input className="form-control" value={itemParaEditar.descricao} onChange={e => setItemParaEditar({...itemParaEditar, descricao: e.target.value})} />
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                <div>
                  <label style={labelStyle}>Cartão</label>
                  <select className="form-control" value={itemParaEditar.cartao || ''} onChange={e => setItemParaEditar({...itemParaEditar, cartao: e.target.value})}>
                    <option value="À Vista">À Vista</option>
                    {cartoes.map(c => <option key={c.id} value={c.nome}>{c.nome}</option>)}
                  </select>
                </div>
                <div>
                  <label style={labelStyle}>Valor Total</label>
                  <input className="form-control" type="number" step="0.01" value={itemParaEditar.valor_total} onChange={e => setItemParaEditar({...itemParaEditar, valor_total: e.target.value})} />
                </div>
              </div>

              <button type="submit" className="btn-primary" style={{ marginTop: '10px' }}>
                <Save size={18} style={{ marginRight: '8px' }} /> Salvar Alteração
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const tHead = { padding: '15px 20px', fontSize: '0.75rem', color: '#64748b', textTransform: 'uppercase', fontWeight: '800' };
const tCell = { padding: '15px 20px', fontSize: '0.9rem' };
const navBtnStyle = { background: 'none', border: 'none', cursor: 'pointer', color: '#4361ee' };
const labelStyle = { fontSize: '0.7rem', fontWeight: '800', color: '#64748b', marginBottom: '5px', display: 'block' };
const overlayStyle = { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 };

export default Listagem;
